import { Component, OnInit, inject } from '@angular/core';
import { BackofficeUser, CreateUserRequest, UpdateUserRequest } from '../../../application/models/backoffice.models';
import { UserManagementService } from '../../../application/services/user-management.service';

@Component({
  selector: 'bo-user-management',
  templateUrl: './user-management.component.html',
  styleUrls: ['./user-management.component.css']
})
export class UserManagementComponent implements OnInit {
  private readonly userManagementService = inject(UserManagementService);

  users: BackofficeUser[] = [];
  selectedUser: BackofficeUser | null = null;
  searchTerm = '';
  isLoading = true;
  isSaving = false;
  showForm = false;

  form = {
    email: '',
    password: '',
    roles: ['ROLE_TRAMITADOR'],
    isActive: true
  };

  roleOptions = [
    { value: 'ROLE_TRAMITADOR', label: 'Tramitador' },
    { value: 'ROLE_ADMIN', label: 'Administrador' }
  ];

  ngOnInit(): void {
    this.loadUsers();
  }

  get filteredUsers(): BackofficeUser[] {
    const term = this.searchTerm.trim().toLowerCase();
    if (!term) return this.users;
    return this.users.filter(user => user.email.toLowerCase().includes(term) || user.roles.join(' ').toLowerCase().includes(term));
  }

  loadUsers(): void {
    this.isLoading = true;
    this.userManagementService.list().subscribe({
      next: users => {
        this.users = users;
        this.isLoading = false;
      },
      error: () => {
        this.users = [];
        this.isLoading = false;
      }
    });
  }

  openCreate(): void {
    this.selectedUser = null;
    this.form = { email: '', password: '', roles: ['ROLE_TRAMITADOR'], isActive: true };
    this.showForm = true;
  }

  openEdit(user: BackofficeUser): void {
    this.selectedUser = user;
    this.form = { email: user.email, password: '', roles: [...user.roles], isActive: user.isActive };
    this.showForm = true;
  }

  closeForm(): void {
    this.showForm = false;
    this.selectedUser = null;
  }

  toggleRole(role: string): void {
    if (this.form.roles.includes(role)) {
      this.form.roles = this.form.roles.filter(item => item !== role);
      return;
    }
    this.form.roles = [...this.form.roles, role];
  }

  save(): void {
    if (!this.form.email || this.form.roles.length === 0) return;

    this.isSaving = true;
    if (this.selectedUser) {
      const request: UpdateUserRequest = {
        email: this.form.email,
        roles: this.form.roles,
        isActive: this.form.isActive
      };
      this.userManagementService.update(this.selectedUser.id, request).subscribe({
        next: () => this.afterSave(),
        error: () => this.isSaving = false
      });
      return;
    }

    const request: CreateUserRequest = {
      email: this.form.email,
      password: this.form.password || 'ChangeMe123',
      roles: this.form.roles,
      isActive: this.form.isActive
    };
    this.userManagementService.create(request).subscribe({
      next: () => this.afterSave(),
      error: () => this.isSaving = false
    });
  }

  toggleActive(user: BackofficeUser): void {
    this.userManagementService.toggleActive(user.id, !user.isActive).subscribe({
      next: updated => user.isActive = updated.isActive
    });
  }

  private afterSave(): void {
    this.isSaving = false;
    this.closeForm();
    this.loadUsers();
  }
}
<div class="space-y-6">
  <div class="bg-white rounded-lg shadow p-6">
    <div class="flex flex-col lg:flex-row lg:items-center lg:justify-between gap-4">
      <div>
        <h3 class="text-lg font-semibold text-gray-900">Gestion de Usuarios</h3>
        <p class="text-sm text-gray-500 mt-1">Administrar tramitadores, administradores y permisos operativos.</p>
      </div>
      <div class="flex gap-3">
        <input type="search" [(ngModel)]="searchTerm" placeholder="Buscar usuario o rol" class="border border-gray-300 rounded-md px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500" />
        <button type="button" (click)="openCreate()" class="px-4 py-2 bg-blue-600 text-white rounded-md text-sm font-medium hover:bg-blue-700">Nuevo usuario</button>
      </div>
    </div>
  </div>

  <div class="bg-white rounded-lg shadow overflow-hidden">
    <div *ngIf="isLoading" class="p-8 text-center text-gray-500">Cargando usuarios...</div>
    <table *ngIf="!isLoading" class="w-full">
      <thead class="bg-gray-50 border-b border-gray-200">
        <tr>
          <th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Usuario</th>
          <th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Roles</th>
          <th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Estado</th>
          <th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Ultimo acceso</th>
          <th class="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase">Acciones</th>
        </tr>
      </thead>
      <tbody class="divide-y divide-gray-200">
        <tr *ngFor="let user of filteredUsers" class="hover:bg-gray-50">
          <td class="px-6 py-4">
            <div class="font-medium text-gray-900">{{ user.email }}</div>
            <div class="text-xs text-gray-500">{{ user.id }}</div>
          </td>
          <td class="px-6 py-4">
            <span *ngFor="let role of user.roles" class="inline-flex mr-2 px-2 py-1 bg-blue-50 text-blue-700 text-xs font-medium rounded-full">{{ role }}</span>
          </td>
          <td class="px-6 py-4">
            <span class="px-2 py-1 text-xs font-medium rounded-full" [class.bg-green-100]="user.isActive" [class.text-green-800]="user.isActive" [class.bg-red-100]="!user.isActive" [class.text-red-800]="!user.isActive">
              {{ user.isActive ? 'Activo' : 'Inactivo' }}
            </span>
          </td>
          <td class="px-6 py-4 text-sm text-gray-500">{{ user.lastLogin ? (user.lastLogin | date: 'dd/MM/yyyy HH:mm') : 'Nunca' }}</td>
          <td class="px-6 py-4 text-right space-x-3">
            <button type="button" (click)="openEdit(user)" class="text-blue-600 hover:text-blue-800 text-sm font-medium">Editar</button>
            <button type="button" (click)="toggleActive(user)" class="text-gray-600 hover:text-gray-900 text-sm font-medium">{{ user.isActive ? 'Desactivar' : 'Activar' }}</button>
          </td>
        </tr>
        <tr *ngIf="filteredUsers.length === 0">
          <td colspan="5" class="px-6 py-8 text-center text-gray-500">No hay usuarios</td>
        </tr>
      </tbody>
    </table>
  </div>

  <div *ngIf="showForm" class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
    <div class="bg-white rounded-lg shadow-lg p-6 w-full max-w-lg">
      <h3 class="text-lg font-semibold text-gray-900 mb-4">{{ selectedUser ? 'Editar usuario' : 'Nuevo usuario' }}</h3>
      <div class="space-y-4">
        <div>
          <label class="block text-sm font-medium text-gray-700 mb-1">Email</label>
          <input type="email" [(ngModel)]="form.email" class="w-full border border-gray-300 rounded-md px-3 py-2" />
        </div>
        <div *ngIf="!selectedUser">
          <label class="block text-sm font-medium text-gray-700 mb-1">Contrasena inicial</label>
          <input type="password" [(ngModel)]="form.password" placeholder="ChangeMe123 si se deja vacio" class="w-full border border-gray-300 rounded-md px-3 py-2" />
        </div>
        <div>
          <label class="block text-sm font-medium text-gray-700 mb-2">Roles</label>
          <label *ngFor="let role of roleOptions" class="inline-flex items-center mr-4 text-sm">
            <input type="checkbox" [checked]="form.roles.includes(role.value)" (change)="toggleRole(role.value)" class="mr-2" />
            {{ role.label }}
          </label>
        </div>
        <label class="inline-flex items-center text-sm">
          <input type="checkbox" [(ngModel)]="form.isActive" class="mr-2" />
          Usuario activo
        </label>
      </div>
      <div class="flex justify-end gap-3 mt-6">
        <button type="button" (click)="closeForm()" class="px-4 py-2 border border-gray-300 rounded-md text-sm">Cancelar</button>
        <button type="button" (click)="save()" [disabled]="isSaving" class="px-4 py-2 bg-blue-600 text-white rounded-md text-sm disabled:opacity-50">{{ isSaving ? 'Guardando...' : 'Guardar' }}</button>
      </div>
    </div>
  </div>
</div>
